        GcOp::Count, GcOp::Step, GcOp::SetPause, GcOp::SetStepMul,
        GcOp::IsRunning, GcOp::Gen, GcOp::Inc,
    ];
    // C: int o = optsnum[luaL_checkoption(L, 1, "collect", opts)];
    let idx = state.check_arg_option(1, Some(b"collect"), OPTS)?;
