323	/// Cross-table weak-sweep used at `collectgarbage("collect")` time.
324	///
325	/// The per-table `entry_is_weakly_dead` check called from `get`/`next_pair`
326	/// undercounts when the same target is held weakly across multiple tables
327	/// (the "bug-in-5.1" case in `testes/gc.lua`): each call inspects only one
328	/// entry and treats the other table's weak Rc as if it were strong.
329	///
330	/// This routine iterates the full list of currently-registered weak tables
331	/// and removes entries whose weak target is held only by weak slots —
332	/// counted across *all* tables in the list. Iterates until the sweep makes
333	/// no further progress so that chain-clears (clearing one entry exposes
334	/// another) settle to a fixed point.
335	pub fn sweep_weak_tables(tables: &[GcRef<LuaTable>]) {
336	    if tables.is_empty() {
337	        return;
338	    }
339	    loop {
340	        let mut any_removed = false;
341	        for t in tables {
342	            let mode = t.weak_mode.get();
343	            if mode == 0 {
344	                continue;
345	            }
346	            let dead_indices: Vec<usize> = {
347	                let entries = t.entries.borrow();
348	                let mut result = Vec::new();
349	                for (i, (k, v)) in entries.iter().enumerate() {
350	                    if entry_is_weakly_dead_global(k, v, mode, tables) {
351	                        result.push(i);
352	                    }
353	                }
354	                result
355	            };
356	            if !dead_indices.is_empty() {
357	                let mut entries = t.entries.borrow_mut();
358	                for &i in dead_indices.iter().rev() {
359	                    entries.swap_remove(i);
360	                }
361	                drop(entries);
362	                any_removed = true;
363	            }
364	        }
365	        if !any_removed {
366	            break;
367	        }
368	    }
369	}
