/// GC operation codes (C: LUA_GC* constants)
#[repr(i32)]
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum GcWhat {
    Stop = 0,
    Restart = 1,
    Collect = 2,
    Count = 3,
    CountB = 4,
    Step = 5,
    SetPause = 6,
    SetStepMul = 7,
    IsRunning = 9,
    Gen = 10,
    Inc = 11,
}

// C: LUA_API int lua_gc (lua_State *L, int what, ...)
// PORT NOTE: C varargs replaced by explicit GcArgs enum; callers supply parameters directly.
pub enum GcArgs {
    Stop,
    Restart,
    Collect,
    Count,
    CountB,
    Step { data: i32 },
    SetPause { value: i32 },
    SetStepMul { value: i32 },
    IsRunning,
    Gen { minormul: i32, majormul: i32 },
    Inc { pause: i32, stepmul: i32, stepsize: i32 },
}

pub fn gc(state: &mut LuaState, args: GcArgs) -> i32 {
    // C: if (g->gcstp & GCSTPGC) return -1;
    if state.global().is_gc_stopped_internally() {
        return -1;
    }
    match args {
        // C: case LUA_GCSTOP: g->gcstp = GCSTPUSR;
        GcArgs::Stop => {
            state.global_mut().set_gc_stop_user();
        }
        // C: case LUA_GCRESTART: luaE_setdebt(g, 0); g->gcstp = 0;
        GcArgs::Restart => {
            {
                let mut g = state.global_mut();
                crate::state::set_debt(&mut *g, 0);
            }
            state.global_mut().clear_gc_stop();
        }
        // C: case LUA_GCCOLLECT: luaC_fullgc(L, 0);
        GcArgs::Collect => {
            state.gc().full_collect();
            // Phase-B stand-in for the C atomic-phase weak-table pass: a
            // cross-table sweep of every weak/ephemeron table reachable
            // from the registry. The per-entry Rc-strong-count check used
            // by `next_pair`/`get` undercounts when the same target is
            // held weakly by multiple tables (the bug-in-5.1 case in
            // `testes/gc.lua`); this global pass closes that gap.
            // Removed in Phase D when real incremental GC clears these.
            let live_weak_tables: Vec<GcRef<lua_types::value::LuaTable>> = {
                let mut g = state.global_mut();
                g.weak_tables_registry.retain(|w| w.strong_count() > 0);
                let mut seen = std::collections::HashSet::<usize>::new();
                g.weak_tables_registry
                    .iter()
                    .filter_map(|w| w.upgrade())
                    .filter_map(|rc| {
                        let id = std::rc::Rc::as_ptr(&rc) as *const () as usize;
                        if seen.insert(id) {
                            Some(GcRef(rc))
                        } else {
                            None
                        }
                    })
                    .collect()
            };
            lua_types::value::sweep_weak_tables(&live_weak_tables);
            drop(live_weak_tables);
            // Phase-B: drain pending __gc finalizers for tables whose user
            // refs have all been dropped. Performed after the weak-table
            // sweep so weak entries are cleared first (matches C-Lua, which
            // runs finalizers after the atomic weak-pass).
            run_pending_finalizers(state);
            // PORT NOTE: Phase B has no per-allocation totalbytes tracking,
            // so total_bytes() only ever shrinks (each `Step` simulates
            // freed memory). Refill to a baseline here so subsequent Step
            // calls have headroom to actually drop count*1024 — the test
            // pattern `collectgarbage(); local x = gcinfo(); collectgarbage('step'); assert(gcinfo()<x)`
            // needs gcinfo to be high enough that decrementing by 1 KB is
            // observable. Removed in Phase D when real GC tracks bytes.
            {
                let mut g = state.global_mut();
                let target_tb = 32_768_isize;
                let cur_tb = g.totalbytes + g.gc_debt;
                if cur_tb < target_tb {
                    g.totalbytes += target_tb - cur_tb;
                }
            }
        }
        // C: case LUA_GCCOUNT: res = cast_int(gettotalbytes(g) >> 10);
        GcArgs::Count => {
            {
                let mut g = state.global_mut();
                crate::state::reclaim_dead_long_strings(&mut *g);
            }
            return (state.global().total_bytes() >> 10) as i32;
        }
        // C: case LUA_GCCOUNTB: res = cast_int(gettotalbytes(g) & 0x3ff);
        GcArgs::CountB => {
            {
                let mut g = state.global_mut();
                crate::state::reclaim_dead_long_strings(&mut *g);
            }
            return (state.global().total_bytes() & 0x3ff) as i32;
        }
        // C: case LUA_GCSTEP: ...
        GcArgs::Step { data } => {
            // C: l_mem debt = 1; lu_byte oldstp = g->gcstp; g->gcstp = 0;
            let old_stp = {
                let mut g = state.global_mut();
                let old = g.gc_stop_flags();
                g.clear_gc_stop();
                old
            };
            if data == 0 {
                // C: luaE_setdebt(g, 0); luaC_step(L);
                {
                    let mut g = state.global_mut();
                    crate::state::set_debt(&mut *g, 0);
                }
                state.gc().step();
            } else {
                // C: debt = cast(l_mem, data) * 1024 + g->GCdebt; luaE_setdebt; luaC_checkGC
                let debt = data as isize * 1024 + state.global().gc_debt();
                {
                    let mut g = state.global_mut();
                    crate::state::set_debt(&mut *g, debt);
                }
                state.gc().check_step();
            }
            state.global_mut().set_gc_stop_flags(old_stp);
            // PORT NOTE: Phase B GC is a no-op for actual object freeing.
            // Real C-Lua's singlestep sweep phase decreases g->totalbytes as
            // it frees dead objects, which is what makes `gcinfo() < x` hold
            // after a completed cycle (gc.lua dosteps). Simulate that by
            // dropping `gc_debt` by 1 KB (one count() unit) when the running
            // total has enough headroom; this leaves totalbytes alone and lets
            // a `Collect` baseline refill replenish room for future steps.
            // Removed in Phase D when real incremental GC lands.
            {
                let mut g = state.global_mut();
                let tb = g.totalbytes + g.gc_debt;
                if tb >= 2048 {
                    g.gc_debt -= 1024;
                }
            }
            // C: if (debt > 0 && g->gcstate == GCSpause) res = 1;
            return if state.global().gc_at_pause() { 1 } else { 0 };
        }
        // C: case LUA_GCSETPAUSE:
        GcArgs::SetPause { value } => {
            // C: res = getgcparam(g->gcpause); setgcparam(g->gcpause, data);
            let old = state.global().gc_pause_param() as i32;
            state.global_mut().set_gc_pause_param(value as u8);
            return old;
        }
        // C: case LUA_GCSETSTEPMUL:
        GcArgs::SetStepMul { value } => {
            let old = state.global().gc_stepmul_param() as i32;
            state.global_mut().set_gc_stepmul_param(value as u8);
            return old;
        }
        // C: case LUA_GCISRUNNING: res = gcrunning(g);
        GcArgs::IsRunning => {
            return state.global().gc_running() as i32;
        }
        // C: case LUA_GCGEN:
        GcArgs::Gen { minormul, majormul } => {
            // C: res = isdecGCmodegen(g) ? LUA_GCGEN : LUA_GCINC;
            let old_mode = if state.global().is_gen_mode() { 10i32 } else { 11i32 };
            if minormul != 0 {
                state.global_mut().genminormul = minormul as u8;
            }
            if majormul != 0 {
                state.global_mut().set_gc_genmajormul(majormul as u8);
            }
            // C: luaC_changemode(L, KGC_GEN);
            state.gc().change_mode(crate::state::GcKind::Generational);
            return old_mode;
        }
        // C: case LUA_GCINC:
        GcArgs::Inc { pause, stepmul, stepsize } => {
            let old_mode = if state.global().is_gen_mode() { 10i32 } else { 11i32 };
            if pause != 0 {
                state.global_mut().set_gc_pause_param(pause as u8);
            }
            if stepmul != 0 {
                state.global_mut().set_gc_stepmul_param(stepmul as u8);
            }
            if stepsize != 0 {
                state.global_mut().gcstepsize = stepsize as u8;
            }
            // C: luaC_changemode(L, KGC_INC);
            state.gc().change_mode(crate::state::GcKind::Incremental);
            return old_mode;
        }
    }
    0
}

