// C: void lua_setwarnf (lua_State *L, lua_WarnFunction f, void *ud)
pub fn set_warn_f(
    state: &mut LuaState,
    f: Option<Box<dyn FnMut(&[u8], bool)>>,
) {
    // C: G(L)->ud_warn = ud; G(L)->warnf = f;
