    state: &mut LuaState,
    bytes: &[u8],
    kind: StringKind,
    hash: u32,
) -> GcRef<LuaStringImpl> {
    // C: o = luaC_newobj(L, tag, totalsize);
    // macros.tsv: luaM_newobject → state.gc().new_obj(tag, sz)
    // TODO(port): register with GC tracking list (state.global_mut().allgc)
    // in Phase D; Phase A–C creates a bare Rc
    let ts = GcRef::new(LuaStringImpl {
        // C: ts->hash = h;
        hash: Cell::new(hash),
        // C: ts->extra = 0;
        extra: Cell::new(0),
        // C: getstr(ts)[l] = '\0';  /* content written by caller via memcpy */
        // PORT NOTE: we receive bytes directly; no separate memcpy step needed
        bytes: Rc::from(bytes),
        kind,
    });
    // PORT NOTE: Phase-B byte tracking for `collectgarbage("count")`. C-Lua's
    // `luaC_newobj` calls `luaM_malloc`, which adds `sizeof(TString) + len + 1`
    // to `g->GCdebt`. Phases A–C bypass that allocator, so without explicit
    // accounting the Lua-visible memory total never reflects string data and
    // tests like `gc.lua`'s string-keys-in-weak-tables block fail. We only
    // track long strings here because short strings are interned (bounded in
    // size, dominated by struct overhead) while long strings are created
    // fresh per call and can carry megabytes of payload that the test relies
    // on observing.
    if matches!(kind, StringKind::Long) {
        let size = bytes.len()
            + std::mem::size_of::<LuaStringImpl>()
            + std::mem::size_of::<usize>();
        let mut g = state.global_mut();
        g.gc_debt += size as isize;
        g.gc_tracked_long_strings.push((Rc::downgrade(&ts.0), size));
    }
    ts
}

