// C: static void close_state(lua_State *L)
fn close_state(state: &mut LuaState) {
    // C: global_State *g = G(L);
    let is_complete = state.global().is_complete();

    // C: if (!completestate(g)) luaC_freeallobjects(L); /* just collect its objects */
    if !is_complete {
